        assert_eq!(f.monto_total, 3480.0);
        assert_eq!(f.estado, "emitida");
        assert_eq!(f.concepto, "Trabajo abril");
        let sesiones = mgr.sesion_list(Some(&cid), None, None, None).await.unwrap();
        assert!(sesiones
            .iter()
            .all(|s| s.factura_id.as_deref() == Some(&fid)));
        // factura_pagar
